namespace sv_9c42120543d94753b76b6a36d0a1430b.Services;

public class AppointmentService
{
    public Task<List<string>> GetDoctorsAsync()
    {
        return Task.FromResult(new List<string>
        {
            "Dr. Smith",
            "Dr. Johnson",
            "Dr. Patel",
            "Dr. Williams"
        });
    }

    public Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateOnly date)
    {
        return Task.FromResult(new List<string>
        {
            "9:00 AM",
            "10:00 AM",
            "11:00 AM",
            "1:00 PM",
            "2:00 PM",
            "3:00 PM"
        });
    }

    /// <summary>
    /// Validates patient and appointment data against server-side business rules.
    /// Returns a dictionary of field name → error messages.
    /// </summary>
    public Task<Dictionary<string, List<string>>> ValidatePatientAsync(
        string email,
        string insuranceProvider,
        string doctor,
        string timeSlot)
    {
        var errors = new Dictionary<string, List<string>>();

        // Simulate outstanding balance check
        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            errors["Email"] = new List<string> { "Account has outstanding balance" };
        }

        // Simulate self-pay restriction
        if (insuranceProvider == "None" && doctor == "Dr. Smith")
        {
            errors["Doctor"] = new List<string> { "Selected doctor does not accept self-pay patients" };
        }

        // Simulate race condition on time slot
        if (timeSlot == "10:00 AM")
        {
            errors["TimeSlot"] = new List<string> { "This slot is no longer available" };
        }

        return Task.FromResult(errors);
    }
}

@page "/book-appointment"
@rendermode InteractiveServer
@using sv_9c42120543d94753b76b6a36d0a1430b.Services
@inject AppointmentService AppointmentService

<PageTitle>Book Appointment</PageTitle>

<h1>Book an Appointment</h1>

<EditForm EditContext="editContext" OnSubmit="HandleSubmit">
    <DataAnnotationsValidator />
    <CustomValidator @ref="customValidator" />

    <h3>Step 1: Patient Information</h3>

    <div class="mb-3">
        <label class="form-label">Patient Name</label>
        <InputText class="form-control" @bind-Value="model.PatientName" />
        <ValidationMessage For="() => model.PatientName" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="model.Email" />
        <ValidationMessage For="() => model.Email" />
    </div>

    <div class="mb-3">
        <label class="form-label">Phone</label>
        <InputText class="form-control" @bind-Value="model.Phone" />
        <ValidationMessage For="() => model.Phone" />
    </div>

    <div class="mb-3">
        <label class="form-label">Insurance Provider</label>
        <InputSelect class="form-select" @bind-Value="model.InsuranceProvider">
            <option value="">-- Select --</option>
            <option value="Aetna">Aetna</option>
            <option value="BlueCross">BlueCross</option>
            <option value="Cigna">Cigna</option>
            <option value="UnitedHealth">UnitedHealth</option>
            <option value="None">None</option>
        </InputSelect>
        <ValidationMessage For="() => model.InsuranceProvider" />
    </div>

    @if (showStep2)
    {
        <h3>Step 2: Appointment Details</h3>

        <div class="mb-3">
            <label class="form-label">Preferred Doctor</label>
            <InputSelect class="form-select" @bind-Value="model.Doctor" @bind:after="OnDoctorChanged">
                <option value="">-- Select --</option>
                @foreach (var doc in doctors)
                {
                    <option value="@doc">@doc</option>
                }
            </InputSelect>
            <ValidationMessage For="() => model.Doctor" />
        </div>

        <div class="mb-3">
            <label class="form-label">Date</label>
            <InputDate class="form-control" @bind-Value="model.AppointmentDate" @bind:after="OnDateChanged" />
            <ValidationMessage For="() => model.AppointmentDate" />
        </div>

        <div class="mb-3">
            <label class="form-label">Time Slot</label>
            <InputSelect class="form-select" @bind-Value="model.TimeSlot">
                <option value="">-- Select --</option>
                @foreach (var slot in timeSlots)
                {
                    <option value="@slot">@slot</option>
                }
            </InputSelect>
            <ValidationMessage For="() => model.TimeSlot" />
        </div>

        <div class="mb-3">
            <label class="form-label">Reason for Visit</label>
            <InputTextArea class="form-control" @bind-Value="model.Reason" rows="3" />
            <ValidationMessage For="() => model.Reason" />
        </div>

        <button type="submit" class="btn btn-primary" disabled="@isSubmitting">
            @(isSubmitting ? "Submitting..." : "Book Appointment")
        </button>
    }
    else
    {
        <button type="button" class="btn btn-secondary" @onclick="CheckAvailability" disabled="@isChecking">
            @(isChecking ? "Checking..." : "Check Availability")
        </button>
    }
</EditForm>

@if (appointmentBooked)
{
    <div class="alert alert-success mt-3">
        Appointment booked successfully!
    </div>
}

@code {
    private EditContext editContext = default!;
    private AppointmentModel model = new();
    private CustomValidator? customValidator;

    private bool showStep2;
    private bool isChecking;
    private bool isSubmitting;
    private bool appointmentBooked;

    private List<string> doctors = new();
    private List<string> timeSlots = new();

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(model);
        doctors = await AppointmentService.GetDoctorsAsync();
    }

    private async Task CheckAvailability()
    {
        customValidator?.ClearErrors();

        // Validate only step 1 fields via annotations
        var isValid = editContext.Validate();
        if (!isValid)
            return;

        isChecking = true;
        try
        {
            // Server-side validation with stub data for step transition
            var errors = await AppointmentService.ValidatePatientAsync(
                model.Email ?? "",
                model.InsuranceProvider ?? "",
                "", // no doctor selected yet
                ""); // no time slot selected yet

            if (errors.Count > 0)
            {
                customValidator!.DisplayErrors(errors);
                return;
            }

            showStep2 = true;
        }
        finally
        {
            isChecking = false;
        }
    }

    private async Task OnDoctorChanged()
    {
        timeSlots = new();
        model.TimeSlot = null;
        if (!string.IsNullOrEmpty(model.Doctor) && model.AppointmentDate.HasValue)
        {
            timeSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                model.Doctor, DateOnly.FromDateTime(model.AppointmentDate.Value));
        }
    }

    private async Task OnDateChanged()
    {
        timeSlots = new();
        model.TimeSlot = null;
        if (!string.IsNullOrEmpty(model.Doctor) && model.AppointmentDate.HasValue)
        {
            timeSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                model.Doctor, DateOnly.FromDateTime(model.AppointmentDate.Value));
        }
    }

    private async Task HandleSubmit()
    {
        customValidator?.ClearErrors();

        if (!editContext.Validate())
            return;

        isSubmitting = true;
        try
        {
            var errors = await AppointmentService.ValidatePatientAsync(
                model.Email ?? "",
                model.InsuranceProvider ?? "",
                model.Doctor ?? "",
                model.TimeSlot ?? "");

            if (errors.Count > 0)
            {
                customValidator!.DisplayErrors(errors);
                return;
            }

            appointmentBooked = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

using System.ComponentModel.DataAnnotations;

namespace sv_9c42120543d94753b76b6a36d0a1430b.Components.Pages;

public class AppointmentModel : IValidatableObject
{
    [Required(ErrorMessage = "Patient name is required.")]
    public string? PatientName { get; set; }

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Invalid email format.")]
    public string? Email { get; set; }

    [Required(ErrorMessage = "Phone is required.")]
    public string? Phone { get; set; }

    [Required(ErrorMessage = "Insurance provider is required.")]
    public string? InsuranceProvider { get; set; }

    public string? Doctor { get; set; }

    public DateTime? AppointmentDate { get; set; }

    public string? TimeSlot { get; set; }

    [MaxLength(500, ErrorMessage = "Reason must be 500 characters or fewer.")]
    public string? Reason { get; set; }

    public IEnumerable<ValidationResult> Validate(ValidationContext validationContext)
    {
        // Step 2 fields are only required when step 2 is visible,
        // but we validate date must be in the future if provided.
        if (AppointmentDate.HasValue && AppointmentDate.Value.Date <= DateTime.Today)
        {
            yield return new ValidationResult(
                "Appointment date must be in the future.",
                new[] { nameof(AppointmentDate) });
        }
    }
}

using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Forms;

namespace sv_9c42120543d94753b76b6a36d0a1430b.Components.Pages;

public class CustomValidator : ComponentBase
{
    [CascadingParameter]
    private EditContext? EditContext { get; set; }

    private ValidationMessageStore? messageStore;

    protected override void OnInitialized()
    {
        messageStore = new ValidationMessageStore(EditContext!);
        EditContext!.OnValidationRequested += (s, e) => messageStore.Clear();
        EditContext!.OnFieldChanged += (s, e) => messageStore.Clear(e.FieldIdentifier);
    }

    public void DisplayErrors(Dictionary<string, List<string>> errors)
    {
        foreach (var (field, messages) in errors)
        {
            foreach (var message in messages)
            {
                messageStore!.Add(EditContext!.Field(field), message);
            }
        }
        EditContext!.NotifyValidationStateChanged();
    }

    public void ClearErrors()
    {
        messageStore?.Clear();
        EditContext?.NotifyValidationStateChanged();
    }
}

